import React, { useState, useEffect } from 'react';
import { useNavigate } from 'react-router-dom';
import axios from 'axios';
import { useAuth } from '../contexts/AuthContext';
import { toast } from 'react-toastify';

const API_URL = process.env.REACT_APP_API_URL || 'http://localhost:5000/api';

const Terms = () => {
  const [terms, setTerms] = useState(null);
  const [loading, setLoading] = useState(true);
  const [accepted, setAccepted] = useState(false);
  const { user, acceptTerms } = useAuth();
  const navigate = useNavigate();

  useEffect(() => {
    fetchTerms();
  }, []);

  const fetchTerms = async () => {
    try {
      const response = await axios.get(`${API_URL}/terms/current`);
      setTerms(response.data);
    } catch (error) {
      console.error('Error fetching terms:', error);
      toast.error('Failed to load terms');
    } finally {
      setLoading(false);
    }
  };

  const handleAccept = async () => {
    if (!accepted) {
      toast.error('Please check the box to accept terms');
      return;
    }

    const result = await acceptTerms(terms.id);
    if (result.success) {
      navigate(user?.role === 'admin' ? '/admin/dashboard' : '/customer/dashboard');
    }
  };

  if (loading) {
    return (
      <div className="min-h-screen flex items-center justify-center">
        <div className="animate-spin rounded-full h-12 w-12 border-b-2 border-green-600"></div>
      </div>
    );
  }

  return (
    <div className="min-h-screen bg-gray-100 py-12 px-4 sm:px-6 lg:px-8">
      <div className="max-w-3xl mx-auto">
        <div className="bg-white shadow rounded-lg overflow-hidden">
          <div className="px-6 py-4 bg-green-600">
            <h1 className="text-xl font-semibold text-white">Terms and Conditions</h1>
            <p className="text-sm text-green-100">Version {terms?.version} • Effective {new Date(terms?.effective_date).toLocaleDateString()}</p>
          </div>
          
          <div className="px-6 py-4">
            <div className="prose max-w-none">
              <p className="text-gray-700 whitespace-pre-line">
                {terms?.content}
              </p>
            </div>
            
            <div className="mt-6 border-t pt-6">
              <div className="flex items-center mb-4">
                <input
                  type="checkbox"
                  id="accept"
                  checked={accepted}
                  onChange={(e) => setAccepted(e.target.checked)}
                  className="h-4 w-4 text-green-600 focus:ring-green-500 border-gray-300 rounded"
                />
                <label htmlFor="accept" className="ml-2 block text-sm text-gray-900">
                  I have read and agree to the Terms and Conditions
                </label>
              </div>
              
              <div className="flex justify-end space-x-3">
                <button
                  onClick={() => navigate(-1)}
                  className="px-4 py-2 border border-gray-300 rounded-md text-sm font-medium text-gray-700 hover:bg-gray-50"
                >
                  Cancel
                </button>
                <button
                  onClick={handleAccept}
                  disabled={!accepted}
                  className="px-4 py-2 bg-green-600 text-white rounded-md text-sm font-medium hover:bg-green-700 disabled:opacity-50 disabled:cursor-not-allowed"
                >
                  Accept Terms
                </button>
              </div>
            </div>
          </div>
        </div>
      </div>
    </div>
  );
};

export default Terms;
